// ── BASE64 IMAGES ──
const DETECTED_IMG = "data:image/jpeg;base64,";
const NORMAL_IMG   = "data:image/jpeg;base64,";

let analyzing = false;
let uploadedFileName = '';
let uploadedFileDataUrl = '';
let scanHistory = JSON.parse(localStorage.getItem('vs_history') || '[]');
let waveformInterval = null;

// ── TAB SWITCHING ──
function switchTab(tab) {
  document.querySelectorAll('.tab-panel').forEach(p => p.classList.remove('active'));
  document.querySelectorAll('.nav-btn').forEach(b => b.classList.remove('active'));
  document.getElementById('tab-' + tab).classList.add('active');
  document.querySelector('[data-tab="' + tab + '"]').classList.add('active');
  if (tab === 'history') renderHistory();
}

// ── IMAGE UPLOAD ──
function handleFileSelect(event) {
  const file = event.target.files[0];
  if (!file) return;
  uploadedFileName = file.name;
  document.getElementById('preview-filename').textContent = file.name;
  document.getElementById('preview-filesize').textContent = formatFileSize(file.size);
  if (file.type.startsWith('image/')) {
    const reader = new FileReader();
    reader.onload = (e) => {
      uploadedFileDataUrl = e.target.result;
      const pi = document.getElementById('preview-img');
      pi.src = e.target.result; pi.style.display = 'block';
    };
    reader.readAsDataURL(file);
  } else {
    document.getElementById('preview-img').style.display = 'none';
    uploadedFileDataUrl = NORMAL_IMG;
  }
  document.getElementById('upload-zone').style.display    = 'none';
  document.getElementById('results-section').style.display = 'none';
  document.getElementById('file-preview').style.display   = 'block';
}

function formatFileSize(bytes) {
  if (bytes < 1024) return bytes + ' B';
  if (bytes < 1048576) return (bytes/1024).toFixed(1) + ' KB';
  return (bytes/1048576).toFixed(1) + ' MB';
}

// ── IMAGE ANALYSIS ──
function startAnalysis() {
  if (analyzing) return;
  analyzing = true;
  document.getElementById('file-preview').style.display    = 'none';
  document.getElementById('results-section').style.display = 'none';
  const loader = document.getElementById('analyzing-state');
  loader.style.display = 'flex';

  // Animated steps
  const steps = [
    { text:'Detecting facial landmarks...', sub:'Running 68-point landmark model...',    step:2, delay:600  },
    { text:'Analyzing GAN artifacts...',    sub:'Comparing with 12M deepfake signatures..', step:3, delay:1200 },
    { text:'Generating heatmap...',         sub:'Mapping manipulation regions...',        step:4, delay:1800 }
  ];
  steps.forEach(s => {
    setTimeout(() => {
      document.getElementById('analyze-status-text').textContent = s.text;
      document.getElementById('analyze-status-sub').textContent  = s.sub;
      const dot = document.querySelector('#step' + s.step + ' .step-dot');
      if (dot) dot.classList.add('done');
    }, s.delay);
  });

  setTimeout(() => {
    analyzing = false;
    loader.style.display = 'none';
    // Reset steps
    document.querySelectorAll('.step-dot').forEach(d => d.classList.remove('done'));
    document.getElementById('analyze-status-text').textContent = 'Initializing CNN Model...';
    document.querySelector('#step1 .step-dot').classList.add('done');

    document.getElementById('original-img').src = uploadedFileDataUrl || NORMAL_IMG;
    document.getElementById('detected-img').src  = DETECTED_IMG;
    const rs = document.getElementById('results-section');
    rs.style.display = 'block';
    rs.classList.remove('results-slide-in');
    void rs.offsetWidth;
    rs.classList.add('results-slide-in');

    addToHistory({ type:'file', name: uploadedFileName || 'image_upload', result:'FAKE', time: new Date().toLocaleString() });
  }, 2400);
}

// ── VIDEO DEMO ──
function startVideoDemo() {
  const vz = document.querySelector('#tab-video .upload-zone');
  const va = document.getElementById('video-analyzing');
  const vr = document.getElementById('video-results');
  vz.style.display = 'none'; vr.style.display = 'none';
  va.style.display = 'flex';

  let frame = 0;
  const total = 156;
  const counter = document.getElementById('video-frame-counter');
  const fi = setInterval(() => {
    frame += Math.floor(Math.random() * 8) + 3;
    if (frame >= total) { frame = total; clearInterval(fi); }
    counter.textContent = `Processing frame ${frame} / ${total}...`;
  }, 80);

  setTimeout(() => {
    va.style.display = 'none';
    buildFrameGrid();
    vr.style.display = 'block';
    vr.classList.remove('results-slide-in'); void vr.offsetWidth; vr.classList.add('results-slide-in');
    addToHistory({ type:'video', name:'video_upload.mp4', result:'FAKE', time: new Date().toLocaleString() });
  }, 3000);
}

function buildFrameGrid() {
  const grid = document.getElementById('frame-grid');
  if (!grid) return;
  grid.innerHTML = '';
  const labels = [
    {f:1, fake:false},{f:8,fake:false},{f:16,fake:true},{f:24,fake:true},
    {f:32,fake:true},{f:40,fake:false},{f:48,fake:true},{f:56,fake:true},
    {f:64,fake:true},{f:72,fake:false},{f:80,fake:true},{f:88,fake:false}
  ];
  labels.forEach(l => {
    const el = document.createElement('div');
    el.className = 'frame-thumb ' + (l.fake ? 'frame-fake' : 'frame-ok');
    el.innerHTML = `<span class="frame-num">F${l.f}</span><span class="frame-badge">${l.fake ? 'FAKE' : 'OK'}</span>`;
    grid.appendChild(el);
  });
}

// ── VOICE DEMO ──
function startVoiceDemo() {
  const vu = document.querySelector('#tab-voice .upload-zone');
  const va = document.getElementById('voice-analyzing');
  const vr = document.getElementById('voice-results');
  vu.style.display = 'none'; vr.style.display = 'none';
  va.style.display = 'flex';
  setTimeout(() => {
    va.style.display = 'none';
    buildVoiceWaveform();
    buildSpectralMap();
    vr.style.display = 'block';
    vr.classList.remove('results-slide-in'); void vr.offsetWidth; vr.classList.add('results-slide-in');
    startWaveformAnimation();
    addToHistory({ type:'audio', name:'audio_upload.mp3', result:'FAKE', time: new Date().toLocaleString() });
  }, 2500);
}

function buildVoiceWaveform() {
  const w = document.getElementById('waveform-voice');
  if (!w) return;
  w.innerHTML = '';
  for (let i = 0; i < 52; i++) {
    const b = document.createElement('div');
    b.className = 'waveform-bar';
    b.style.cssText = `height:${Math.random()*75+10}%;background:${Math.random()>.6?'#f43f5e':'#6366f1'};width:6px;min-width:6px;border-radius:3px;flex-shrink:0;transition:height .15s ease;`;
    w.appendChild(b);
  }
}

function startWaveformAnimation() {
  if (waveformInterval) clearInterval(waveformInterval);
  waveformInterval = setInterval(() => {
    const bars = document.querySelectorAll('#waveform-voice .waveform-bar');
    bars.forEach(b => { b.style.height = (Math.random()*75+10) + '%'; });
  }, 150);
}

function buildSpectralMap() {
  const sm = document.getElementById('spectral-map');
  if (!sm) return;
  sm.innerHTML = '';
  const freqs = ['20Hz','100Hz','500Hz','1kHz','4kHz','8kHz','16kHz','20kHz'];
  freqs.forEach((f, i) => {
    const row = document.createElement('div');
    row.className = 'spectral-row';
    const isAnomaly = i >= 5;
    const intensity = isAnomaly ? Math.random()*40+60 : Math.random()*40+10;
    row.innerHTML = `
      <span class="spectral-freq">${f}</span>
      <div class="spectral-bar-wrap"><div class="spectral-bar" style="width:${intensity}%;background:${isAnomaly?'#f43f5e':'#6366f1'}"></div></div>
      ${isAnomaly ? '<span class="spectral-anomaly">!</span>' : ''}
    `;
    sm.appendChild(row);
  });
}

// ── PLATFORM SELECTOR ──
function selectPlatform(btn) {
  const alreadyActive = btn.classList.contains('active');
  document.querySelectorAll('.platform-btn').forEach(b => b.classList.remove('active'));
  const input = document.getElementById('social-url-input');
  if (alreadyActive) {
    input.placeholder = 'Select a platform above or paste any URL...';
    input.value = '';
    return;
  }
  btn.classList.add('active');
  input.placeholder = btn.getAttribute('data-placeholder');
  input.value = '';
  input.focus();
}

// ── SOCIAL SCAN ──
function runSocialScan() {
  const url = document.getElementById('social-url-input').value.trim();
  if (!url) { alert('Please enter a URL first.'); return; }
  document.getElementById('social-results').style.display  = 'none';
  document.getElementById('social-scanning').style.display = 'flex';
  setTimeout(() => {
    document.getElementById('social-scanning').style.display = 'none';
    document.getElementById('social-results').style.display  = 'block';
    const intBox = document.getElementById('integrity-box');
    intBox.style.display = 'flex';
    intBox.closest('.social-grid').classList.add('has-integrity');
    addScanItem(url);
    addToHistory({ type:'url', name:url, result:'FAKE', time: new Date().toLocaleString() });
    document.getElementById('social-url-input').value = '';
  }, 2000);
}

const socialScanItems = [];
function addScanItem(url) {
  socialScanItems.unshift(url);
  renderScanList();
}
function renderScanList() {
  const list = document.getElementById('scan-list');
  if (!list) return;
  if (!socialScanItems.length) {
    list.innerHTML = '<p style="color:var(--slate-500);font-size:.85rem;padding:.5rem 0">No scans yet.</p>';
    return;
  }
  list.innerHTML = socialScanItems.slice(0,5).map(url => `
    <div class="scan-item">
      <div class="scan-thumb"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" style="width:18px;height:18px"><circle cx="12" cy="12" r="10"/><path d="M2 12h20M12 2a15.3 15.3 0 0 1 4 10 15.3 15.3 0 0 1-4 10 15.3 15.3 0 0 1-4-10 15.3 15.3 0 0 1 4-10z"/></svg></div>
      <div class="scan-info"><p class="scan-name">${url}</p><p class="scan-source">Scanned just now · AI deepfake confirmed</p></div>
      <span class="badge-fake">FAKE</span>
    </div>`).join('');
}

// ── HISTORY ──
function addToHistory(item) {
  scanHistory.unshift(item);
  localStorage.setItem('vs_history', JSON.stringify(scanHistory));
}
function clearHistory() {
  scanHistory = [];
  localStorage.removeItem('vs_history');
  renderHistory();
}
function renderHistory() {
  const list  = document.getElementById('history-list');
  const empty = document.getElementById('history-empty');
  if (!list || !empty) return;
  if (!scanHistory.length) { list.innerHTML=''; empty.style.display='block'; return; }
  empty.style.display = 'none';
  const icons = {
    file:  '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" style="width:18px;height:18px"><rect x="3" y="3" width="18" height="18" rx="2"/><circle cx="8.5" cy="8.5" r="1.5"/><polyline points="21 15 16 10 5 21"/></svg>',
    video: '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" style="width:18px;height:18px"><polygon points="23 7 16 12 23 17 23 7"/><rect x="1" y="5" width="15" height="14" rx="2"/></svg>',
    audio: '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" style="width:18px;height:18px"><path d="M12 2a3 3 0 0 0-3 3v7a3 3 0 0 0 6 0V5a3 3 0 0 0-3-3z"/><path d="M19 10v2a7 7 0 0 1-14 0v-2"/></svg>',
    url:   '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" style="width:18px;height:18px"><circle cx="12" cy="12" r="10"/><path d="M2 12h20"/></svg>'
  };
  const typeLabel = { file:'Image upload', video:'Video upload', audio:'Audio upload', url:'Social URL' };
  list.innerHTML = scanHistory.map(item => `
    <div class="history-item">
      <div class="history-item-icon">${icons[item.type]||icons.file}</div>
      <div class="history-item-info">
        <p class="history-item-name">${item.name}</p>
        <p class="history-item-meta">${typeLabel[item.type]||'Scan'} · ${item.time}</p>
      </div>
      <span class="history-badge-fake">${item.result}</span>
    </div>`).join('');
}

// ── INIT ──
document.addEventListener('DOMContentLoaded', () => {
  renderScanList();
  renderHistory();
});